module.render:
const color = args.color || 'var(--accent-color)';
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const gap = Math.max(0, Math.min(40, Number.isFinite(parseFloat(args.gap)) ? parseFloat(args.gap) : 6));
const br = Math.max(0, Math.min(20, Number.isFinite(parseFloat(args.barradius)) ? parseFloat(args.barradius) : 4));
const bh = Math.max(0.8, Math.min(4, Number.isFinite(parseFloat(args.barheight)) ? parseFloat(args.barheight) : 1.5));
const showDur = String(args.showduration) === 'true';
const tasks = [];
sections.forEach((s) => {
  const m = String(s || '').trim().match(/^([\s\S]*?)[|:]\s*(\d+)\s*[-‚Äì ]\s*(\d+)\s*$/);
  if (!m) return;
  const a = parseInt(m[2], 10), b = parseInt(m[3], 10);
  tasks.push({ name: m[1].trim(), start: Math.min(a, b), end: Math.max(a, b) });
});
if (!tasks.length) return `<div class="mdp-mod-gantt">(each section must be "Name | start end")</div>`;
let units = parseInt(args.units, 10) || 0;
if (!units) units = Math.max(...tasks.map((t) => t.end), 1);
const colLabels = String(args.labels || '').split(',').map((x) => x.trim()).filter(Boolean);
let head = '';
if (colLabels.length) {
  head = `<div class="mdp-gt-row mdp-gt-head"><div class="mdp-gt-name"></div><div class="mdp-gt-track" style="grid-template-columns:repeat(${units},1fr);">` +
    Array.from({ length: units }, (_, i) => `<div class="mdp-gt-col">${esc(colLabels[i] || (i + 1))}</div>`).join('') + `</div></div>`;
}
let rows = '';
tasks.forEach((t) => {
  const dur = t.end - t.start + 1;
  const inner = showDur ? esc(dur) : (t.start === t.end ? '‚óÜ' : '');
  rows += `<div class="mdp-gt-row"><div class="mdp-gt-name">${esc(t.name)}</div>` +
    `<div class="mdp-gt-track" style="grid-template-columns:repeat(${units},1fr);">` +
    `<div class="mdp-gt-bar" style="grid-column:${t.start} / ${t.end + 1};">${inner}</div></div></div>`;
});
return `\n\n<div class="mdp-mod-gantt" style="--gt-color:${color}; --gt-radius:${br}px; --gt-barh:${bh}em; gap:${gap}px;">${head}${rows}</div>\n\n`;
